const data = $input.item.json;

const body = {
  message: 'chore: add quality score to system prompt [auto-eval]',
  content: Buffer.from(data.updatedPrompt).toString('base64'),
  branch: data.branch,
  sha: data.promptFileSha
};

return [{ json: {
  commitBody: body,
  owner: data.owner,
  repo: data.repo,
  promptPath: data.promptPath,
  stats: data.stats,
  improved: data.improved,
  pr_number: data.pr_number
}}];

// Decode eval set + system prompt, extract baseline, emit one item per eval case.
// Each item carries the shared metadata so the game node and aggregator can read it.
const trigger = $('Execute Workflow Trigger').first().json;
const evalFileData = $('Fetch Eval Set').first().json;
const promptFileData = $('Fetch System Prompt').first().json;

const evalB64 = (evalFileData.content || '').replace(/\n/g, '');
let evals;
try {
  evals = JSON.parse(Buffer.from(evalB64, 'base64').toString('utf8'));
} catch(e) { throw new Error('Could not parse eval set: ' + e.message); }

const promptB64 = (promptFileData.content || '').replace(/\n/g, '');
const currentPrompt = Buffer.from(promptB64, 'base64').toString('utf8');
const promptFileSha = promptFileData.sha;

let baseline = null;
const headerMatch = currentPrompt.match(/<!--\s*QUALITY_SCORE([\s\S]*?)-->/);
if (headerMatch) {
  try { baseline = JSON.parse(headerMatch[1].trim()); } catch(e) {}
}
const cleanPrompt = currentPrompt.replace(/<!--\s*QUALITY_SCORE[\s\S]*?-->\s*\n*/g, '').trim();

const shared = {
  cleanPrompt:       cleanPrompt,
  baseline:          baseline,
  branch:            trigger.branch,
  owner:             trigger.owner,
  repo:              trigger.repo,
  pr_number:         trigger.pr_number,
  max_iterations:    trigger.max_iterations || 40,
  prompt_path:       trigger.system_prompt_path || 'agents/akinator/system-prompt.md',
  promptFileSha:     promptFileSha,
  min_success_rate:  trigger.min_success_rate  !== undefined ? parseFloat(trigger.min_success_rate)  : 50,
  max_avg_iterations: trigger.max_avg_iterations !== undefined ? parseFloat(trigger.max_avg_iterations) : 30
};

// One item per eval case — all carrying the shared metadata
return evals.map(function(evalCase) {
  return { json: Object.assign({}, evalCase, shared) };
});

// Aggregate all per-game results, compare vs baseline, build updated system prompt.
const all = $input.all();
if (!all || all.length === 0) throw new Error('No eval results to aggregate');

const meta    = all[0].json;
const baseline = meta.baseline;
const cleanPrompt = meta.cleanPrompt;
const minRate  = parseFloat(meta.min_success_rate  || 50);
const maxIters = parseFloat(meta.max_avg_iterations || 30);

const results = all.map(function(it) {
  return { iterations: it.json.iter, success: it.json.success,
           model: it.json.model, tokens_used: it.json.tokens_used };
});

const successes    = results.filter(function(r) { return r.success; });
const successRate  = Math.round((successes.length / results.length) * 1000) / 10;
const avgIter      = Math.round(results.reduce(function(s,r) { return s+r.iterations; }, 0) / results.length * 10) / 10;
const totalTokens  = results.reduce(function(s,r) { return s+r.tokens_used; }, 0);
const tokensPerGame = Math.round(totalTokens / results.length);

const newStats = {
  model:            meta.model || results[0].model,
  total_games:      results.length,
  successful_games: successes.length,
  success_rate:     successRate,
  avg_iterations:   avgIter,
  total_tokens:     totalTokens,
  tokens_per_game:  tokensPerGame,
  evaluated_at:     new Date().toISOString()
};

const firstRun = !baseline;
let improved = false;
if (firstRun) {
  improved = successRate >= minRate && avgIter <= maxIters;
} else {
  improved = successRate > parseFloat(baseline.success_rate || 0)
          && avgIter    < parseFloat(baseline.avg_iterations || 999);
}
newStats.first_run       = firstRun;
newStats.thresholds_used = firstRun ? { min_success_rate: minRate, max_avg_iterations: maxIters } : null;

const updatedPrompt = '<!-- QUALITY_SCORE\n' + JSON.stringify(newStats, null, 2) + '\n-->\n\n' + cleanPrompt;

return [{ json: {
  results:      results,
  stats:        newStats,
  baseline:     baseline,
  first_run:    firstRun,
  improved:     improved,
  updatedPrompt: updatedPrompt,
  promptFileSha: meta.promptFileSha,
  promptPath:    meta.prompt_path,
  owner:         meta.owner,
  repo:          meta.repo,
  branch:        meta.branch,
  pr_number:     meta.pr_number
}}];

// Set up initial game state — one item per eval case.
const item = $input.item.json;
const model = $env.EVAL_MODEL || 'google/gemini-2.5-flash-preview';
return [{ json: Object.assign({}, item, {
  history: [
    { role: 'system', content: item.cleanPrompt },
    { role: 'user',   content: item.chatMessage }
  ],
  iter:       0,
  success:    false,
  done:       false,
  tokens_used: 0,
  is_guess:   false,
  model:      model
}) }];

// ONE API call: Akinator's turn.
const item = $input.item.json;
const apiKey = $env.OPENROUTER_API_KEY;
if (!apiKey) throw new Error('OPENROUTER_API_KEY not set');

const res = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://openrouter.ai/api/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' },
  body: JSON.stringify({ model: item.model, temperature: 0.1, messages: item.history })
});
const reply   = res.choices[0].message.content.trim();
const tokens  = (res.usage || {}).total_tokens || 0;
const isGuess = /is your character|are you thinking of|i think it.s|i believe it.*is|my answer is|i have reached/i.test(reply);

return [{ json: Object.assign({}, item, {
  history:             item.history.concat([{ role: 'assistant', content: reply }]),
  iter:                item.iter + 1,
  tokens_used:         item.tokens_used + tokens,
  is_guess:            isGuess,
  last_akinator_reply: reply
}) }];

// ONE API call: simulated user's turn.
const item = $input.item.json;
const apiKey = $env.OPENROUTER_API_KEY;
if (!apiKey) throw new Error('OPENROUTER_API_KEY not set');

const userSim = [
  'You are roleplaying as a user in a guessing game. Your scenario: ' + item.context + '.',
  'Your mindset going into the game: ' + item.thoughts,
  '',
  'Rules:',
  '- Answer every question from the host with ONLY one of: Yes / No / Unknown / Probably / Probably not',
  '- Use your knowledge of the character described in your scenario to answer accurately',
  '- If the host makes a direct guess naming a character, reply Yes only if that is the character in your scenario, otherwise No',
  '- Never reveal the character name or any identifying detail unprompted \u2014 only confirm or deny explicit guesses'
].join('\n');

const res = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://openrouter.ai/api/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: item.model, temperature: 0.1,
    messages: [{ role: 'system', content: userSim }, { role: 'user', content: item.last_akinator_reply }]
  })
});
const userReply = res.choices[0].message.content.trim();
const tokens    = (res.usage || {}).total_tokens || 0;
const success   = item.is_guess && userReply.trim().toLowerCase().startsWith('yes');
const done      = success || item.iter >= item.max_iterations;

return [{ json: Object.assign({}, item, {
  history:        item.history.concat([{ role: 'user', content: userReply }]),
  tokens_used:    item.tokens_used + tokens,
  success:        success,
  done:           done,
  last_user_reply: userReply
}) }];
